def generate(seed):
    """
    Compute the sum of the first n terms of a linear recurrence and its intersection with a quadratic equation.
    The problem requires the solver to apply the formula for the sum of a linear recurrence and then solve a quadratic equation.
    This introduces a hidden identity and a dimension lift to increase the reasoning depth and diversity.
    """
    rng = random.Random(seed)

    a = rng.randint(1, 10)  # First term
    b = rng.randint(1, 10)  # Second term
    r = rng.randint(2, 10)  # Common ratio
    n = rng.randint(5, 15)  # Number of terms

